CREATE OR REPLACE FUNCTION public.apply_to_project_for_app(p_project_id uuid, p_subject text, p_message text, p_files jsonb DEFAULT '[]'::jsonb)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_profile_id uuid;
  v_owner_id uuid;
  v_application_id uuid;
begin
  v_profile_id := public.app_current_profile_id();

  if v_profile_id is null then
    raise exception 'profile_not_found';
  end if;

  select profile_id into v_owner_id
  from public.projects
  where id = p_project_id;

  if v_owner_id = v_profile_id then
    raise exception 'cannot_apply_to_own_project';
  end if;

  select id into v_application_id
  from public.project_applications
  where project_id = p_project_id
    and profile_id = v_profile_id;

  if v_application_id is not null then
    raise exception 'already_applied';
  end if;

  insert into public.project_applications (
    project_id,
    profile_id,
    subject,
    message,
    attachments_count,
    files
  )
  values (
    p_project_id,
    v_profile_id,
    p_subject,
    p_message,
    jsonb_array_length(coalesce(p_files, '[]'::jsonb)),
    coalesce(p_files, '[]'::jsonb)
  )
  returning id into v_application_id;

  return v_application_id;
end;
$function$

CREATE OR REPLACE FUNCTION public.request_connection_for_app(p_receiver_profile_id uuid, p_message text DEFAULT NULL::text)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_profile_id uuid;
  v_request_id uuid;
begin
  v_profile_id := public.app_current_profile_id();

  if v_profile_id is null then
    raise exception 'profile_not_found';
  end if;

  insert into public.connection_requests (
    requester_profile_id,
    receiver_profile_id,
    message
  )
  values (v_profile_id, p_receiver_profile_id, p_message)
  on conflict (requester_profile_id, receiver_profile_id)
  do update set
    status = 'pending',
    message = excluded.message,
    updated_at = now()
  returning id into v_request_id;

  return v_request_id;
end;
$function$
